use std::fs::read_to_string;
use std::path::{Path, PathBuf};
use std::collections::HashMap;

fn load_config_from_dir(directory: &Path) -> Result<HashMap<String, String>, Box<dyn std::error::Error>> {
    let mut config_map = HashMap::new();

    if !directory.is_dir() {
        return Err(format!("The path provided is not a directory: {}", directory.display()).into());
    }

    for entry in std::fs::read_dir(directory)? {
        let entry = entry?;
        let path = entry.path();
        if path.extension().map_or(false, |ext| ext == "conf") {
            let filename = path.file_stem().unwrap().to_string_lossy().into_owned();
            match read_to_string(&path) {
                Ok(content) => {
                    config_map.insert(filename, content);
                }
                Err(e) => { 
                    eprintln!("Could not read file {:?}: {}", path, e); 
                }
            }
        }
    }

    Ok(config_map)
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let temp_dir = PathBuf::from("temp_configs");
    if !temp_dir.exists() {
        std::fs::create_dir(&temp_dir)?;
        std::fs::write(temp_dir.join("api_key.conf"), "SECRET:123").unwrap();
        std::fs::write(temp_dir.join("db_url.conf"), "postgres://user:pass@localhost/task").unwrap();
    }

    let configs = load_config_from_dir(&temp_dir)?;

    for (key, value) in &configs {
        println!("Loaded configuration for {}: {}", key, value);
    }

    Ok(())
}

use std::fs::File;
use std::io::{self, Read, BufReader};

struct LogRecord {
    timestamp: u64,
    status_code: u16,
}

fn analyze_log_file(path: &str) -> io::Result<Vec<LogRecord>> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);
    let mut records = Vec::new();

    let mut buffer = String::new();
    let mut line_count = 0;

    for line in io::BufRead::lines(reader) {
        buffer.clear();
        line_count += 1;
        match line? {
            l => { 
                if l.is_empty() { continue; }
                let parts: Vec<&str> = l.split("|").collect();
                if parts.len() >= 3 {
                    if let Ok(timestamp) = parts[0].parse::<u64>() {
                        if let Ok(status_code) = parts[1].parse::<u16>() {
                            records.push(LogRecord { timestamp, status_code });
                        }
                    }
                }
            }
        }
    }
    Ok(records)
}

