use std::fs::File;
use std::io::{self, Write, Read};
use std::path::PathBuf;

struct ConfigItem {
    name: String,
    value: u32,
}

fn main() -> io::Result<()> {
    let paths = vec![
        PathBuf::from("data1.txt"),
        PathBuf::from("data2.txt")
    ];

    let mut processed_items: Vec<ConfigItem> = Vec::new();

    for path in paths {
        if !path.exists() { 
            continue;
        }

        println!("Processing path: {}", path.display());

        let mut file = File::open(&path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?;

        for line in contents.lines() {
            if let Some((name, value)) = parse_line(line) {
                processed_items.push(ConfigItem { name: name.to_string(), value });
            }
        }
    }

    let mut output_file = File::create("output_config.json")?;
    writeln!(output_file, "{{")?;
    for (i, item) in processed_items.iter().enumerate() {
        if i > 0 { 
            writeln!(output_file, ",")?;
        }
        writeln!(output_file, "  \"{}\": {}", item.name, item.value)?;
    }
    writeln!(output_file, "}}")?;

    Ok(())
}

fn parse_line(line: &str) -> Option<(&str, u32)> {
    let parts: Vec<&str> = line.split("=").collect();
    if parts.len() == 2 {
        let name = parts[0].trim();
        let value_str = parts[1].trim();
        return Some((name, value_str.parse().ok()?));
    }
    None
}

use std::io;
use std::path::{Path, PathBuf};

struct EmailQueue {
    outgoing_files: Vec<PathBuf>,
}

impl EmailQueue {
    fn new(initial_paths: Vec<PathBuf>) -> Self {
        EmailQueue { outgoing_files: initial_paths }
    }

    fn add_file(&mut self, path: PathBuf) -> io::Result<()> {
        if !self.outgoing_files.contains(&path) {
            self.outgoing_files.push(path.clone());
            println!("Queued file: {}", path.display());
        }
        Ok(())
    }

    fn list_pending(&self) -> Vec<String> {
        self.outgoing_files.iter().map(|p| p.to_string_lossy().into_owned()).collect()
    }
}

fn main() -> io::Result<()> {
    let mut queue = EmailQueue::new(vec![
        PathBuf::from("test_mail_1.txt"),
        PathBuf::from("report_2024.dat"),
    ]);

    queue.add_file(PathBuf::from("new_message.log"))?;

    println!("n--- Pending Files ---n");
    for file_path in queue.list_pending() {
        println!("{}", file_path);
    }

    Ok(())
}

use std::fs::File;
use std::io::{self, Write};

struct SimulationResult {
    matrix_data: Vec<f64>,
    rows: usize,
    cols: usize,
}

fn save_simulation_matrix(result: &SimulationResult, filepath: &str) -> io::Result<()> {
    let mut file = File::create(filepath)?;
    for i in 0..result.rows {
        for j in 0..result.cols {
            let index = i * result.cols + j;
            if let Some(&value) = result.matrix_data.get(index) {
                write!(file, "{:.10}", value)?;
                if j < result.cols - 1 {
                    write!(file, "  ")?;
                }
            }
        }
        writeln!(file)?;
    }
    Ok(())
}

fn main() -> io::Result<()> {
    let data_points = vec![
        0.123456789,
        0.987654321,
        0.500000000
    ];
    let rows = 2;
    let cols = 3;

    let result = SimulationResult {
        matrix_data: vec![
            data_points[0],
            data_points[1],
            data_points[2]
        ],
        rows: 2,
        cols: 3
    };

    save_simulation_matrix(&result, "sim_output.dat")?;
    println!("Successfully saved simulation matrix to sim_output.dat");
    Ok(())
}
